using System;
using System.Collections.Generic;
using System.Net.WebSockets;
using System.Text;
using System.Threading;
using System.Threading.Tasks;
using System.Web.Script.Serialization;
using GTA;
using GTA.Native;

namespace ModProject
{
    public class Mod : Script
    {
        private const string WsUrl = "ws://127.0.0.1:60080";
        private const int RoseGiftId = 5655;
        private const int ActionQueueLimit = 100;
        private static readonly TimeSpan TriggerCooldown = TimeSpan.FromSeconds(30);

        private ClientWebSocket _ws;
        private CancellationTokenSource _cts;
        private readonly Queue<Action> _mainThreadActions = new Queue<Action>();
        private readonly object _queueLock = new object();
        private DateTime _lastTriggerUtc = DateTime.MinValue;

        public Mod()
        {
            Tick += OnTick;
            Interval = 50;
            _cts = new CancellationTokenSource();
            Task.Run(() => ConnectAndListenAsync(_cts.Token));
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                try { _cts?.Cancel(); } catch { }
                try { _ws?.Dispose(); } catch { }
                try { _cts?.Dispose(); } catch { }
            }
            base.Dispose(disposing);
        }

        private void OnTick(object sender, EventArgs e)
        {
            Action[] pending;
            lock (_queueLock)
            {
                if (_mainThreadActions.Count == 0) return;
                pending = _mainThreadActions.ToArray();
                _mainThreadActions.Clear();
            }
            foreach (var action in pending)
            {
                try { action(); } catch { }
            }
        }

        private void EnqueueAction(Action action)
        {
            lock (_queueLock)
            {
                if (_mainThreadActions.Count >= ActionQueueLimit) return;
                _mainThreadActions.Enqueue(action);
            }
        }

        private async Task ConnectAndListenAsync(CancellationToken token)
        {
            while (!token.IsCancellationRequested)
            {
                try
                {
                    using (var ws = new ClientWebSocket())
                    {
                        _ws = ws;
                        await ws.ConnectAsync(new Uri(WsUrl), token);

                        var subMsg = "{\"type\":\"serviceSignalSub\",\"payload\":{\"signal\":\"IM_MESSAGE_TRANSPORT\"}}";
                        await SendMessageAsync(ws, subMsg, token);

                        var buffer = new byte[8192];
                        var sb = new StringBuilder();

                        while (ws.State == WebSocketState.Open && !token.IsCancellationRequested)
                        {
                            var segment = new ArraySegment<byte>(buffer);
                            var result = await ws.ReceiveAsync(segment, token);
                            if (result.MessageType == WebSocketMessageType.Close) break;

                            sb.Append(Encoding.UTF8.GetString(buffer, 0, result.Count));
                            if (result.EndOfMessage)
                            {
                                var raw = sb.ToString();
                                sb.Clear();
                                ProcessRawMessage(raw);
                            }
                        }
                    }
                }
                catch (OperationCanceledException) { break; }
                catch (Exception) { /* reconnect */ }

                if (!token.IsCancellationRequested)
                {
                    try { await Task.Delay(3000, token); } catch { break; }
                }
            }
        }

        private static async Task SendMessageAsync(ClientWebSocket ws, string msg, CancellationToken token)
        {
            var bytes = Encoding.UTF8.GetBytes(msg);
            var segment = new ArraySegment<byte>(bytes);
            await ws.SendAsync(segment, WebSocketMessageType.Text, true, token);
        }

        private void ProcessRawMessage(string raw)
        {
            try
            {
                var serializer = new JavaScriptSerializer();
                var envelope = serializer.Deserialize<Dictionary<string, object>>(raw);
                if (envelope == null) return;

                if (!envelope.TryGetValue("type", out var typeObj)) return;
                var type = typeObj as string;
                if (type != "WebcastGiftMessage") return;

                if (!envelope.TryGetValue("giftId", out var giftIdObj))
                {
                    if (!envelope.TryGetValue("gift_id", out giftIdObj)) return;
                }

                int giftId;
                if (giftIdObj is int i)
                    giftId = i;
                else if (giftIdObj is long l)
                    giftId = (int)l;
                else if (giftIdObj is string s && int.TryParse(s, out var parsed))
                    giftId = parsed;
                else
                    giftId = Convert.ToInt32(giftIdObj);

                if (giftId == RoseGiftId)
                {
                    EnqueueAction(TriggerRoseEffect);
                }
            }
            catch { /* malformed message, ignore */ }
        }

        private void TriggerRoseEffect()
        {
            var now = DateTime.UtcNow;
            if ((now - _lastTriggerUtc) < TriggerCooldown) return;
            _lastTriggerUtc = now;

            var playerPed = Game.Player?.Character;
            if (playerPed == null || !playerPed.IsAlive) return;

            /* 1. Weather → Rain */
            World.Weather = Weather.Rain;

            /* 2. Health → half */
            playerPed.Health = Math.Max(1, playerPed.Health / 2);

            /* 3. Wanted level → 3 stars */
            Game.Player.WantedLevel = 3;

            /* 4. Give sniper rifle */
            playerPed.Weapons.Give(WeaponHash.SniperRifle, 10, true, true);
        }
    }
}
